<?php require_once __DIR__.'/../config.php'; if(is_admin()) redirect('index.php'); $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){csrf_verify(); $stmt=db()->prepare('SELECT * FROM admins WHERE email=?'); $stmt->execute([$_POST['email']]); $admin=$stmt->fetch(); if($admin && password_verify($_POST['password'],$admin['password'])){$_SESSION['admin_id']=$admin['id']; redirect('index.php');} $error='Email atau password salah.';} ?>
